1	const countLiveNeighbors = (grid: boolean[][], r: number, c: number): number => {
2	  let count = 0;
3	  for (let dr = -1; dr <= 1; dr++) {
4	    for (let dc = -1; dc <= 1; dc++) {
5	      if (dr === 0 && dc === 0) continue;
6	      const nr = r + dr;
7	      const nc = c + dc;
8	      if (nr >= 0 && nr < grid.length && nc >= 0 && nc < grid[r].length && grid[nr][nc]) {
9	        count++;
10	      }
11	    }
12	  }
13	  return count;
14	};
15	
16	export function nextGeneration(grid: boolean[][]): boolean[][] {
17	  return grid.map((row, r) =>
18	    row.map((cell, c) => {
19	      const neighbors = countLiveNeighbors(grid, r, c);
20	      return cell ? neighbors === 2 || neighbors === 3 : neighbors === 3;
21	    })
22	  );
23	}
