2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[true]])).toEqual([[false]]);
10	  });
11	  it("should return empty grid for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[true, true]])).toEqual([[false, false]]);
13	  });
14	  it("should keep a block (2x2) unchanged (still life)", () => {
15	    expect(nextGeneration([[true, true], [true, true]])).toEqual([[true, true], [true, true]]);
16	  });
17	  it("should reproduce a dead cell with exactly 3 live neighbors", () => {
18	    expect(nextGeneration([[true, true], [true, false]])).toEqual([[true, true], [true, true]]);
19	  });
